import React from 'react';
import TabelaRelatorioEconomico from '../components/TabelaRelatorioEconomico';

const anoAtual = new Date().getFullYear();
const dataLinhas = [
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
];

export default function RelatorioPrimeiroSemestre() {
  let razaoSocial = '';
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      if (obj.razaoSocial) razaoSocial = obj.razaoSocial;
    }
  } catch {}
  return <TabelaRelatorioEconomico datasPadrao={dataLinhas} razaoSocial={razaoSocial} semestre="SEM1" ano={anoAtual} />;
}
